// Best-effort proof. The postcondition reduces to:
    //   r1.v@ == empty && r2.v@ == empty ==> r1 == r2
    // which requires Vec extensional-equality (vec1@ == vec2@ ==> vec1 == vec2).
    // vstd does not provide such an axiom for Vec (only for Seq, Set, Map, slice,
    // and array). Without introducing a new axiom (which is forbidden), this
    // synthetic obligation cannot be discharged.
    assert(
        (
            r1@ == Seq::<K>::empty()
            && r1.valid()
            && r2@ == Seq::<K>::empty()
            && r2.valid()
        ) ==> det_new_equal(r1, r2)
    ) by {
        broadcast use vstd::std_specs::vec::group_vec_axioms;
        broadcast use vstd::seq::group_seq_axioms;
        broadcast use vstd::seq_lib::group_seq_lib_default;
        if r1@ == Seq::<K>::empty() && r2@ == Seq::<K>::empty() {
            assert(r1.v@ =~= r2.v@);
            assert(r1.v@ == r2.v@);
        }
    };
